            for (int w = lane_id; w < BLOCK_W/2; w += warp_size) {
                set_m0(s_input + off_h1 + 2*__builtin_amdgcn_readfirstlane(w));
                global_load_lds_dword(off_h0 * sizeof(IO_DTYPE) + w*sizeof_dword, input);
            }
        }
    }

    int ki = 0;
    #pragma unroll
    for(int d = 0; d < KD; d ++) {
        #pragma unroll
        for(int h = 0; h < KH; h++) {
            #pragma unroll
            for(int w = 0; w < KW; w++) {
                weight_reg[d][h][w] = kernel[ki++];
            }
        }
    }
    float bias_value = 0.0f;
    if (bias != nullptr)
        bias_value = bias[out_channel];

    s_waitcnt_vmcnt<0>();
    __syncthreads();

    constexpr int num_outputs = BLOCK_H * BLOCK_W;
    constexpr int KW_PACK = 2;
    constexpr int KWR = div_up(KW, KW_PACK);

    for (int oi = KW_PACK*threadIdx.x; oi < num_outputs; oi += KW_PACK*blockDim.x) {
        const int oh = oi / BLOCK_W;
        const int ow = oi % BLOCK_W;

        const int srci0 = (oh) * padded_W + (ow);
        float sum0 = bias_value;
        float sum1 = bias_value;

        #pragma unroll
        for(int d = 0; d < KD; d ++) {
            #pragma unroll
            for(int h = 0; h < KH; h++) {
                uint32_t input_reg[KWR];

                #pragma unroll
                for(int w = 0; w < KW; w+=KW_PACK) {
                    int src_off = d*(padded_H * padded_W) + (PaddingH + h - KH/2)*padded_W + (PaddingW + w - KW/2);
                    reinterpret_cast<uint32_t&>(input_reg[w/KW_PACK]) = ds_read_b32(s_input + srci0, src_off*sizeof(IO_DTYPE));
                }

                #pragma unroll
                for(int w = 0; w < KW-1; w+=2) {
                    float v0 = (float)(reinterpret_cast<IO_DTYPE*>(&input_reg[w/KW_PACK])[0]);
                    float v1 = (float)(reinterpret_cast<IO_DTYPE*>(&input_reg[w/KW_PACK])[1]);
                    float nv0 = (float)(reinterpret_cast<IO_DTYPE*>(&input_reg[w/KW_PACK+1])[0]);
                    sum0 += weight_reg[d][h][w+0] * v0;
                    sum0 += weight_reg[d][h][w+1] * v1;
                    sum1 += weight_reg[d][h][w+0] * v1;
                    sum1 += weight_reg[d][h][w+1] * nv0;
                }

                constexpr int last_w = KW - 1;
                if constexpr (last_w % 2 == 0) {
                    float v0 = (float)(reinterpret_cast<IO_DTYPE*>(&input_reg[last_w/KW_PACK])[0]);
                    float v1 = (float)(reinterpret_cast<IO_DTYPE*>(&input_reg[last_w/KW_PACK])[1]);
                    sum0 += weight_reg[d][h][last_w] * v0;
                    sum1 += weight_reg[d][h][last_w] * v1;
                }
            }
        }

        output[oh * oW + ow + 0] = (IO_DTYPE)(sum0);
        output[oh * oW + ow + 1] = (IO_DTYPE)(sum1);
    }
}

